const WHITE_SPACE_REGEX = /^\s*$/;

function NonDisplayingActionDirective({
  node,
}: {
  node?: {
    data?: {
      hName?: string;
      hProperties?: Record<string, unknown>;
    };
  };
}): React.ReactElement | null {
  const directiveName = node?.data?.hName ?? "app-action";
  const payload = node?.data?.hProperties ?? {};
  logger.trace(`[bgthread] directive`, {
    safe: {
      name: directiveName,
    },
    sensitive: {
      payload: payload,
    },
  });
  return null;
}

const generateComponents = (
  textSize: string,
  conversationId: ConversationId | null,
  hideCodeBlocks: boolean | undefined,
  cwd: GitCwd | null,
): Partial<Components> => {
  const baseTextStyle = `${textSize}`;
  const components: Partial<Components> & Record<string, unknown> = {
    code({ className, children, ...rest }) {
      const content = typeof children === "string" ? children : "";
      // @ts-expect-error - inline is added by rehypeInlineCodeProperty
      const inline = rest.inline;
      if (inline) {
        const rawContent = content ?? "";
        const atMentionPath = rawContent.startsWith("@")
          ? rawContent.slice(1)
          : null;
        if (atMentionPath != null && isFileReference(atMentionPath)) {
          const parsedReference = parseFileReference(atMentionPath);
          return (
            <FileLink
              className={className}
              reference={parsedReference}
              cwd={cwd}
            />
          );
        }
        const inlineMarkdownLink = parseInlineMarkdownLink(rawContent);
        if (
          inlineMarkdownLink &&
          (isFileReference(inlineMarkdownLink.href) ||
            isAbsoluteFilesystemReference(inlineMarkdownLink.href))
        ) {
          const parsedReference = parseFileReference(inlineMarkdownLink.href);
          const formattedLabel = formatFileReferenceLabel(parsedReference);
          const displayLabel = formatFileReferenceDisplayLabel(parsedReference);
          const label = getFileLinkDisplayLabel({
            trimmedChildText: inlineMarkdownLink.label,
            href: inlineMarkdownLink.href,
            parsedReference,
            displayLabel,
            formattedLabel,
          });
          return (
            <FileLink
              className={className}
              reference={parsedReference}
              label={label}
              tooltipText={formattedLabel}
              cwd={cwd}
            />
          );
        }
        if (inlineMarkdownLink && isAppMentionPath(inlineMarkdownLink.href)) {
          return (
            <AppChip
              label={parseMentionLabel(inlineMarkdownLink.label)}
              href={inlineMarkdownLink.href}
              tooltipText={inlineMarkdownLink.href}
            />
          );
        }
        if (inlineMarkdownLink && isAgentMentionPath(inlineMarkdownLink.href)) {
          const conversationId = getConversationIdFromAgentMentionPath(
            inlineMarkdownLink.href,
          );
          if (conversationId == null) {
            return children;
          }
          return (
            <AgentChip
              conversationId={conversationId}
              label={parseMentionLabel(inlineMarkdownLink.label)}
              tooltipText={inlineMarkdownLink.href}
            />
          );
        }
        const isSkillMention = SKILL_INLINE_PATTERN.test(rawContent);
        if (isSkillMention) {
          const mentionText = parseMentionLabel(rawContent);
          return <SkillChip label={mentionText} />;
        }
        return (
          <span
            className={clsx(
              markdownStyles.inlineMarkdown,
              inlineCodeTextStyle,
              "blend bg-token-text-code-block-background rounded-sm px-1.5 py-0.5 leading-none extension:bg-token-foreground/10 electron:bg-token-list-hover-background/60",
            )}
          >
            {children}
          </span>
        );
      }

      if (hideCodeBlocks) {
        return null;
      }

      const language = className
        ?.split(" ")
        .find((value) => value.startsWith("language-"))
        ?.split("-")[1];

      if (language === "mermaid") {
        return (
          <LazyCodeBlock
            language={language}
            content={content ?? ""}
            renderVisible={() => (
              <MermaidDiagram
                code={content ?? ""}
                fallback={
                  <CodeSnippet
                    wrapperClassName="my-2"
                    content={content ?? ""}
                    language={language}
                  />
                }
              />
            )}
          />
        );
      }

      return (
        <LazyCodeBlock
          language={language}
          content={content}
          renderVisible={() => (
            <CodeSnippet
              wrapperClassName="my-2"
              content={content}
              language={language}
              {...rest}
            />
          )}
        />
      );
    },

    pre({ children }) {
      return <>{children}</>;
    },

    p({ children }) {
      return <p className={clsx(baseTextStyle, "my-2")}>{children}</p>;
    },

    h1({ children }) {
      return (
        <h1
          className={clsx(
            baseHeadingStyle,
            markdownStyles.headingInlineCode,
            "heading-lg mt-5 mb-2",
          )}
        >
          {children}
        </h1>
      );
    },

    h2({ children }) {
      return (
        <h2
          className={clsx(
            baseHeadingStyle,
            markdownStyles.headingInlineCode,
            "heading-base mt-4 mb-2",
          )}
        >
          {children}
        </h2>
      );
    },

    h3({ children }) {
      return (
        <h3
          className={clsx(
            baseHeadingStyle,
            markdownStyles.headingInlineCode,
            "text-size-chat mt-3 mb-1.5",
          )}
        >
          {children}
        </h3>
      );
    },

    ul({ className, children }) {
      const isTaskList = className?.includes("contains-task-list") ?? false;
      return (
        <ul
          className={clsx(
            baseTextStyle,
            "mt-0 mb-4 ",
            isTaskList ? "list-none pl-0" : "list-disc pl-4",
            className,
          )}
        >
          {children}
        </ul>
      );
    },

    ol({ className, children, start }) {
      const isTaskList = className?.includes("contains-task-list") ?? false;
      if (isTaskList && orderedListHasOnlyTaskItems(children)) {
        return (
          <ol
            className={clsx(
              baseTextStyle,
              "mt-0 mb-4 list-none pl-0",
              className,
            )}
          >
            {children}
          </ol>
        );
      }
      const groups = groupOrderedListItems(Children.toArray(children), start);
      return (
        <>
          {groups.map((group, groupIndex) => {
            const paddingClassName = getOrderedListPaddingClassName(
              group.digits,
            );
            const marginClass = getOrderedListMarginClass(
              groupIndex,
              groups.length,
            );
            return (
              <ol
                key={`ol-${group.start}`}
                className={clsx(
                  baseTextStyle,
                  "list-decimal",
                  marginClass,
                  paddingClassName,
                )}
                start={group.start}
              >
                {group.items}
              </ol>
            );
          })}
        </>
      );
    },

    li({ className, children }) {
      const isTaskListItem = className?.includes("task-list-item") ?? false;
      return (
        <li
          className={clsx(
            baseTextStyle,
            "mb-1.5",
            isTaskListItem && "list-none",
            className,
          )}
        >
          {children}
        </li>
      );
    },

    a({ href, children }) {
      const childText = Children.toArray(children)
        .map((child) => {
          if (typeof child === "string" || typeof child === "number") {
            return String(child);
          }
          if (isValidElement(child)) {
            const childProps = child.props as Record<string, unknown>;
            if (typeof childProps.text === "string") {
              return childProps.text;
            }
            if (typeof childProps.label === "string") {
              return childProps.label;
            }
            if (typeof childProps.children === "string") {
              return childProps.children;
            }
            if (typeof childProps.children === "number") {
              return String(childProps.children);
            }
          }
          return "";
        })
        .join("");
      const trimmedChildText = childText.trim();
      if (href && isAppMentionPath(href)) {
        const fallbackLabel = href.slice("app://".length);
        const appLabel = parseMentionLabel(trimmedChildText || fallbackLabel);
        return <AppChip label={appLabel} href={href} tooltipText={href} />;
      }
      if (href && isAgentMentionPath(href)) {
        const conversationId = getConversationIdFromAgentMentionPath(href);
        if (conversationId == null) {
          return <>{children}</>;
        }
        const fallbackLabel = href.slice("agent://".length);
        const agentLabel = parseMentionLabel(trimmedChildText || fallbackLabel);
        return (
          <AgentChip
            conversationId={conversationId}
            label={agentLabel}
            tooltipText={href}
          />
        );
      }
      const isSkillLink =
        trimmedChildText.startsWith("$") || href?.endsWith("SKILL.md");
      if (isSkillLink) {
        const rawLabel =
          parseMentionLabel(trimmedChildText) ||
          href?.split("/").slice(-2, -1)[0]?.replace(/-/g, " ") ||
          href ||
          "";
        const label = parseMentionLabel(rawLabel);
        const tooltipText = href ?? trimmedChildText.slice(1);
        return (
          <SkillChip label={label} href={href} tooltipText={tooltipText} />
        );
      }
      if (
        href &&
        (isFileReference(href) || isAbsoluteFilesystemReference(href))
      ) {
        const parsedReference = parseFileReference(href);
        const formattedLabel = formatFileReferenceLabel(parsedReference);
        const displayLabel = formatFileReferenceDisplayLabel(parsedReference);
        const label = getFileLinkDisplayLabel({
          trimmedChildText,
          href,
          parsedReference,
          displayLabel,
          formattedLabel,
        });
        return (
          <FileLink
            reference={parsedReference}
            label={label}
            tooltipText={formattedLabel}
            cwd={cwd}
          />
        );
      }
      return (
        <a
          href={href}
          className="text-token-text-link-foreground underline decoration-current decoration-opacity-50 decoration-[0.5px]"
          target="_blank"
          rel="noopener noreferrer"
          onClick={(event) => {
            if (!href || !isExternalUrl(href)) {
              return;
            }
            event.preventDefault();
            messageBus.dispatchMessage("open-in-browser", {
              url: normalizeExternalUrl(href),
            });
          }}
        >
          {children}
        </a>
      );
    },

    img: MarkdownImage,

    blockquote({ children }) {
      return (
        <blockquote
          className={clsx(
            baseTextStyle,
            "my-3 border-l-2 border-gray-300 pl-4 italic",
          )}
        >
          {children}
        </blockquote>
      );
    },

    hr() {
      return <hr className="my-4 border-t border-gray-300" />;
    },

    table({ children }) {
      return (
        <table className={clsx(baseTextStyle, "my-3 w-full border-collapse")}>
          {children}
        </table>
      );
    },

    thead({ children }) {
      return <thead className="bg-token-foreground/5">{children}</thead>;
    },

    tbody({ children }) {
      return <tbody>{children}</tbody>;
    },

    tr({ children }) {
      return <tr className="border-token-border border-b">{children}</tr>;
    },

    th({ children }) {
      return (
        <th className="p-1 text-left font-semibold text-token-foreground">
          {children}
        </th>
      );
    },

    td({ children }) {
      return <td className="p-1">{children}</td>;
    },
  };

  function CodeCommentDirectiveComponent(
    props: React.ComponentProps<typeof CodeCommentDirectiveRenderer>,
  ): React.ReactElement | null {
    return (
      <CodeCommentDirectiveRenderer
        {...props}
        conversationId={conversationId}
      />
    );
  }

  components[WHAM_TASK_STUB_DIRECTIVE_NAME] = ProposedTaskDirectiveRenderer;
  components[APP_ACTION_ADD_INBOX_ITEM_DIRECTIVE_NAME] =
    NonDisplayingActionDirective;
  components[APP_ACTION_ARCHIVE_THREAD_DIRECTIVE_NAME] =
    NonDisplayingActionDirective;
  components[CODE_COMMENT_DIRECTIVE_NAME] = CodeCommentDirectiveComponent;
  components[AUTOMATION_UPDATE_DIRECTIVE_NAME] =
    AutomationUpdateDirectiveRenderer;

  return components;
};

const Markdown = memo(function MarkdownComponent({
  children,
  id,
  className,
  components,
  textSize = "text-size-chat",
  conversationId = null,
  hideCodeBlocks,
  fadeType = "none",
  cwd,
}: {
  children: string;
  id?: string;
  className?: string;
  components?: Partial<Components>;
  textSize?: string;
  conversationId?: ConversationId | null;
  hideCodeBlocks?: boolean;
  fadeType?: "none" | "indexed";
  cwd: GitCwd | null;
}): React.ReactElement {
  const generatedId = useId();
  const blockId = id ?? generatedId;
  const segmenter = useMemo(() => {
    try {
      return new Intl.Segmenter(undefined, { granularity: "word" });
    } catch {
      return null;
    }
  }, []);
  const initialComponents = useMemo(
    (): Partial<Components> =>
      generateComponents(textSize, conversationId, hideCodeBlocks, cwd),
    [conversationId, cwd, hideCodeBlocks, textSize],
  );
  const remarkRehypeOptions = useMemo(() => {
    if (fadeType !== "indexed") {
      return undefined;
    }
    return {
      handlers: {
        text: (_state: unknown, node: MdastText): Array<HastElement> => {
          return segmentText(node.value, segmenter).map((segment) => ({
            type: "element",
            tagName: "span",
            properties: { className: markdownStyles.fadeIn },
            children: [{ type: "text", value: segment }],
          }));
        },
      },
    };
  }, [fadeType, segmenter]);

  return (
    <div
      className={clsx(
        "[&>*:first-child]:mt-0",
        fadeType === "indexed" && markdownStyles.markdownRoot,
        className,
      )}
    >
      <ReactMarkdown
        key={`${blockId}-block`}
        urlTransform={(value, key, node: HastElement): string => {
          if (
            key === "href" &&
            node.tagName === "a" &&
            (isAppMentionPath(value) || isAgentMentionPath(value))
          ) {
            return value;
          }
          if (key === "src" && node.tagName === "img") {
            if (
              DATA_IMAGE_URL_PATTERN.test(value) ||
              isAbsoluteFilesystemPath(value)
            ) {
              return value;
            }
          }
          return defaultUrlTransform(value);
        }}
        rehypePlugins={[
          rehypeInlineCodeProperty,
          [rehypeKatex, { strict: "ignore" }],
        ]}
        remarkPlugins={[
          remarkGfm,
          remarkMath,
          remarkBreaks,
          remarkFixBrokenOrderedLists,
          remarkPreserveWindowsPaths,
          remarkDirective,
          codexRemarkDirective,
          remarkFileMentions,
          remarkSkillMentions,
          remarkStripCitationMarkers,
          fallbackDirective,
        ]}
        remarkRehypeOptions={remarkRehypeOptions}
        components={{
          ...initialComponents,
          ...components,
        }}
      >
        {children}
      </ReactMarkdown>
    </div>
  );
});

Markdown.displayName = "Markdown";

export { Markdown };

function getOrderedListMarginClass(
  groupIndex: number,
  groupCount: number,
): string {
  if (groupCount <= 1) {
    return "mt-1.5 mb-3";
  }
  if (groupIndex === 0) {
    return "mt-1.5 mb-0";
  }
  if (groupIndex === groupCount - 1) {
    return "mt-0 mb-3";
  }
  return "my-0";
}

function segmentText(
  text: string,
  segmenter: Intl.Segmenter | null,
): Array<string> {
  if (segmenter == null) {
    const segments = Array.from(text.match(/\s*\S+(?:\s+|$)/g) ?? []);
    if (segments.length > 0 || text.length === 0) {
      return segments;
    }
    return [text];
  }
  const segments: Array<string> = [];
  for (const { segment, isWordLike } of segmenter.segment(text)) {
    if (WHITE_SPACE_REGEX.test(segment) || !isWordLike) {
      const lastIndex = Math.max(segments.length - 1, 0);
      segments[lastIndex] ??= "";
      segments[lastIndex] += segment;
      continue;
    }
    segments.push(segment);
  }
  return segments;
}

function orderedListHasOnlyTaskItems(children: React.ReactNode): boolean {
  const listItems = Children.toArray(children).filter((child) =>
    isValidElement(child),
  );
  if (listItems.length === 0) {
    return false;
  }
  return listItems.every((child) => {
    const childProps = child.props as { className?: string };
    return childProps.className?.includes("task-list-item") ?? false;
  });
}

function isExternalUrl(href: string): boolean {
  return EXTERNAL_URL_PATTERN.test(href);
}

function normalizeExternalUrl(href: string): string {
  if (/^www\./i.test(href)) {
    return `https://${href}`;
  }
  return href;
}

function parseMentionLabel(rawLabel: string): string {
  if (rawLabel.startsWith("$[") && rawLabel.endsWith("]")) {
    return rawLabel.slice(2, -1);
  }
  if (rawLabel.startsWith("$")) {
    return rawLabel.slice(1);
  }
  return rawLabel;
}

function parseInlineMarkdownLink(
  rawContent: string,
): { label: string; href: string } | null {
  const match = rawContent.match(/^\[([^\]\n]+)\]\(([^)\n]+)\)$/);
  if (!match) {
    return null;
  }
  const label = match[1]?.trim() ?? "";
  const href = match[2]?.trim() ?? "";
  if (label.length === 0 || href.length === 0) {
    return null;
  }
  return { label, href };
}

function getFileLinkDisplayLabel({
  trimmedChildText,
  href,
  parsedReference,
  displayLabel,
  formattedLabel,
}: {
  trimmedChildText: string;
  href: string;
  parsedReference: ParsedFileReference;
  displayLabel: string;
  formattedLabel: string;
}): string {
  const useReferenceLabel =
    trimmedChildText.length === 0 ||
    trimmedChildText === href ||
    trimmedChildText === formattedLabel;
  if (useReferenceLabel) {
    return displayLabel;
  }
  return maybeNormalizeFileLinkLabel(
    trimmedChildText,
    parsedReference,
    formattedLabel,
  );
}

function maybeNormalizeFileLinkLabel(
  label: string,
  hrefReference: ParsedFileReference,
  formattedHrefLabel: string,
): string {
  if (!hasFileReferenceLocation(hrefReference)) {
    return label;
  }
  const locationSuffix = formattedHrefLabel.slice(hrefReference.path.length);
  if (locationSuffix.length === 0) {
    return label;
  }
  if (isFileReference(label)) {
    const parsedLabelReference = parseFileReference(label);
    if (isMatchingFileTarget(parsedLabelReference.path, hrefReference.path)) {
      return `${parsedLabelReference.path}${locationSuffix}`;
    }
  }
  if (label.endsWith(locationSuffix)) {
    return label;
  }
  return `${label}${locationSuffix}`;
}

function hasFileReferenceLocation(reference: ParsedFileReference): boolean {
  return (
    reference.line !== undefined ||
    reference.column !== undefined ||
    reference.endLine !== undefined ||
    reference.endColumn !== undefined
  );
}

function isMatchingFileTarget(leftPath: string, rightPath: string): boolean {
  const normalizedLeft = normalizeFsPath(leftPath).replace(/\/+$/, "");
  const normalizedRight = normalizeFsPath(rightPath).replace(/\/+$/, "");
  if (normalizedLeft === normalizedRight) {
    return true;
  }
  if (
    normalizedLeft.length > 0 &&
    normalizedRight.endsWith(`/${normalizedLeft}`)
  ) {
    return true;
  }
  if (
    normalizedRight.length > 0 &&
    normalizedLeft.endsWith(`/${normalizedRight}`)
  ) {
    return true;
  }
  const leftBasename = normalizedLeft.split("/").pop();
  const rightBasename = normalizedRight.split("/").pop();
  if (!leftBasename || !rightBasename) {
    return false;
  }
  if (leftBasename !== rightBasename) {
    return false;
  }
  return normalizedLeft === leftBasename || normalizedRight === rightBasename;
}

function MarkdownImage({
  src,
  alt,
  title,
  className,
}: React.ComponentProps<"img">): React.ReactElement | null {
  const intl = useIntl();
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);
  const [failedSrc, setFailedSrc] = useState<string | null>(null);
  const rawSrc = src ?? "";
  const hasSrc = rawSrc.length > 0;
  const isAbsolutePath = hasSrc && isAbsoluteFilesystemPath(rawSrc);
  const { data, isLoading } = useFetchFromVSCode("read-file-binary", {
    params: { path: isAbsolutePath ? rawSrc : "" },
    queryConfig: {
      enabled: isAbsolutePath,
    },
  });

  if (!hasSrc) {
    return null;
  }

  const contentsBase64 = data?.contentsBase64 ?? null;
  const resolvedSrc =
    isAbsolutePath && contentsBase64
      ? toDataUrl({ path: rawSrc, contentsBase64 })
      : rawSrc;

  if (isAbsolutePath && isLoading && !contentsBase64) {
    return null;
  }

  const hasLoadError = failedSrc === resolvedSrc;
  const imageAlt = alt ?? "";
  const imagePreviewButtonLabel =
    imageAlt ||
    intl.formatMessage({
      id: "markdown.imagePreviewButton",
      defaultMessage: "Open image preview",
      description:
        "Accessible label for a markdown image button when no alt text is provided",
    });
  const disabledImageFallbackLabel =
    imageAlt ||
    intl.formatMessage({
      id: "markdown.imageUnavailable",
      defaultMessage: "Image unavailable",
      description:
        "Accessible label for a markdown image fallback when the image fails to load and no alt text is provided",
    });

  if (hasLoadError) {
    return (
      <button
        type="button"
        disabled
        className={clsx(
          markdownImageClassName,
          "bg-token-toolbar-hover-background text-token-description-foreground inline-flex min-h-24 min-w-24 max-w-full cursor-default items-center justify-center border-0 p-0",
        )}
        aria-label={disabledImageFallbackLabel}
        title={title}
      >
        <ImageSquare className="icon-lg" />
      </button>
    );
  }

  return (
    <ImagePreviewDialog
      src={resolvedSrc}
      alt={imageAlt}
      open={isPreviewOpen}
      onOpenChange={setIsPreviewOpen}
      contentMaxWidthClassName="max-w-[min(90vw,calc(var(--thread-content-max-width)+16rem))]"
      triggerContent={
        <button
          type="button"
          className="inline-block max-w-full cursor-zoom-in border-0 bg-transparent p-0 align-top"
          aria-label={imagePreviewButtonLabel}
        >
          <img
            className={clsx(markdownImageClassName, className)}
            src={resolvedSrc}
            alt={imageAlt}
            title={title}
            loading="lazy"
            onError={() => {
              setFailedSrc(resolvedSrc);
            }}
          />
        </button>
      }
    />
  );
}

function toDataUrl({
  path,
  contentsBase64,
}: {
  path: string;
  contentsBase64: string;
}): string {
  const mimeType = lookup(path);
  const resolvedMimeType =
    typeof mimeType === "string" ? mimeType : "application/octet-stream";
  return `data:${resolvedMimeType};base64,${contentsBase64}`;
}

function LazyCodeBlock({
  language: _language,
  content,
  renderVisible,
}: {
  language?: string;
  content: string;
  renderVisible: () => React.ReactElement;
}): React.ReactElement {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    if (isVisible) {
      return;
    }
    const node = containerRef.current;
    if (!node) {
      return;
    }
    if (typeof IntersectionObserver === "undefined") {
      setTimeout(() => {
        setIsVisible(true);
      }, 0);
      return;
    }
    const observer = new IntersectionObserver(
      (entries) => {
        if (entries.some((entry) => entry.isIntersecting)) {
          setIsVisible(true);
          observer.disconnect();
        }
      },
      {
        rootMargin: "600px 0px",
      },
    );
    observer.observe(node);
    return (): void => {
      observer.disconnect();
    };
  }, [isVisible]);

  if (isVisible) {
    return renderVisible();
  }

  return (
    <div ref={containerRef} className="my-2">
      <pre className="bg-token-text-code-block-background/10 border-token-input-background overflow-x-auto rounded-lg border p-2 text-size-chat">
        <code>{content}</code>
      </pre>
    </div>
  );
}
